using System;
using System.Collections.Generic;

class Program
{
    static List<string> todoList = new List<string>();

    static void ShowMenu()
    {
        Console.WriteLine("\n=== YAPILACAKLAR LISTESI ===");
        Console.WriteLine("1. Gorev Ekle");
        Console.WriteLine("2. Gorevleri Listele");
        Console.WriteLine("3. Gorev Sil");
        Console.WriteLine("4. Cikis");
    }

    static void AddTask(string task)
    {
        todoList.Add(task);
        Console.WriteLine($"Eklendi: '{task}'");
    }

    static void ListTasks()
    {
        if (todoList.Count == 0)
        {
            Console.WriteLine("Liste bos.");
            return;
        }

        for (int i = 0; i < todoList.Count; i++)
        {
            Console.WriteLine($"{i + 1}. {todoList[i]}");
        }
    }

    static void RemoveTask(int index)
    {
        if (index >= 0 && index < todoList.Count)
        {
            Console.WriteLine($"Silindi: '{todoList[index]}'");
            todoList.RemoveAt(index);
        }
        else
        {
            Console.WriteLine("Gecersiz numara.");
        }
    }

    static void Main()
    {
        // Simulasyon: kullanici girisleri onceden tanimli
        ShowMenu();

        Console.WriteLine("\n> Secim: 1");
        AddTask("Markete git");

        Console.WriteLine("\n> Secim: 1");
        AddTask("Kod yaz");

        Console.WriteLine("\n> Secim: 1");
        AddTask("Spor yap");

        Console.WriteLine("\n> Secim: 2");
        ListTasks();

        Console.WriteLine("\n> Secim: 3 (1. gorevi sil)");
        RemoveTask(0);

        Console.WriteLine("\n> Secim: 2");
        ListTasks();

        Console.WriteLine("\n> Secim: 4");
        Console.WriteLine("Programdan cikiliyor...");
    }
}
